from itertools import combinations
class Solution:
    def maxScore(self, a, b):
        best = None
        for idxs in combinations(range(len(b)), 4):
            score = sum(a[j] * b[idxs[j]] for j in range(4))
            if best is None or score > best:
                best = score
        return best

