class Solution:
    def maxScore(self, a, b):
        NEG = float('-inf')
        dp = [NEG, NEG, NEG, NEG]
        for x in b:
            for j in range(3, -1, -1):
                prev = dp[j - 1] if j > 0 else 0
                if prev != NEG:
                    cand = prev + a[j] * x
                    if cand > dp[j]:
                        dp[j] = cand
        return dp[3]

