var maxScore = function(a, b) {
    const NEG = -Infinity;
    const dp = [NEG, NEG, NEG, NEG];
    for (const x of b) {
        for (let j = 3; j >= 0; j--) {
            const prev = j > 0 ? dp[j - 1] : 0;
            if (prev !== NEG) {
                const cand = prev + a[j] * x;
                if (cand > dp[j]) dp[j] = cand;
            }
        }
    }
    return dp[3];
};
